import osfrom dataclasses import dataclassfrom pathlib import Pathfrom dotenv import load_dotenvload_dotenv(Path(__file__).resolve().parent / ".env")BOT_TOKEN = os.getenv("BOT_TOKEN", "")PROJECT_DIR = Path(__file__).resolve().parentDATABASE_PATH = Path(os.getenv("DATABASE_PATH", PROJECT_DIR / "data" / "matchbot.db"))# Отображаемое имя -> подстроки в названии турнира на soccer365.ruLEAGUE_PATTERNS: dict[str, list[str]] = {	"РПЛ": ["/competitions/13/"],	"Ла Лига": ["/competitions/16/"],	"Лига 1(Франция)": ["/competitions/18/"],	"АПЛ": ["/competitions/12/"],	"Бундеслига": ["/competitions/17/"],	"Серия А": ["/competitions/15/"],	"ЧМ 26": ["/competitions/742/"],}AVAILABLE_LEAGUES = list(LEAGUE_PATTERNS.keys())@dataclass(frozen=True)class MatchEvent:	type: str  # goal | update | finished	match_title: str	text: str	league: str | None = None	def __str__(self) -> str:		return self.textdef league_matches_tournament(league_name: str, tournament_name: str) -> bool:	patterns = LEAGUE_PATTERNS.get(league_name, [])	return any(pattern.lower() in tournament_name.lower() for pattern in patterns)